sys_script_client.script:
/**
 * onLoad Set mandatory and read-only fields on Checkin form
 * 
 * @author GEM/Quynhttn - 14.05.2026
 * @returns {none}
 */
function onLoad() {
   // Configure field properties
   var fieldConfigs = [
		{
			fieldName: 'u_checkin_date',
			isMandatory: true,
			isReadOnly: false
		},
		{
			fieldName: 'u_recruit_id',
			isMandatory: true,
			isReadOnly: false
		},
		{
			fieldName: 'u_bid_id',
			isMandatory: true,
			isReadOnly: false
		},
		{
			fieldName: 'u_office_email',
			isMandatory: true,
			isReadOnly: false
		},
		{
			fieldName: 'u_channel',
			isMandatory: true,
			isReadOnly: false
		},
		{
			fieldName: 'u_candidate_id',
			isMandatory: true,
			isReadOnly: false
		},
		{
			fieldName: 'u_checkin_id',
			isMandatory: false,
			isReadOnly: true
		},
		{
			fieldName: 'u_candidate_email',
			isMandatory: false,
			isReadOnly: true
		},
		{
			fieldName: 'u_candidate_name',
			isMandatory: false,
			isReadOnly: true
		},
		{
			fieldName: 'u_candidate_phone',
			isMandatory: false,
			isReadOnly: true
		},
		{
			fieldName: 'u_tof',
			isMandatory: false,
			isReadOnly: true
		},
		{
			fieldName: 'u_tof_okr',
			isMandatory: false,
			isReadOnly: true
		}
	];

	// Apply mandatory and read-only settings
	fieldConfigs.forEach(function(field) {
		g_form.setMandatory(field.fieldName, field.isMandatory);
		g_form.setReadOnly(field.fieldName, field.isReadOnly);
	});
}
